import { useState, useEffect } from "react"
import "./index.css"

type TimerMode = "focus" | "shortbreak" | "longbreak"

const FOCUS_TIME = 25 * 60 // 25 minutes in seconds
const SHORT_BREAK_TIME = 5 * 60 // 5 minutes in seconds
const LONG_BREAK_TIME = 15 * 60 // 15 minutes in seconds

const getModeText = (mode: TimerMode): string => {
  switch (mode) {
  case "focus":
    return "Focus";
  case "shortbreak":
    return "Short Break";
  case "longbreak":
    return "Long Break";
default:
  return "Timer";
}

const getInitialTime = (mode: TimerMode): number => {
  switch (mode) {
  case "focus":
    return FOCUS_TIME;
  case "shortbreak":
    return SHORT_BREAK_TIME;
case "longbreak":
  return LONG_BREAK_TIME;
default:
  return 0;
}

function PomodoroTimer() {
  const [isRunning, setIsRunning] = useState(false)
  const [time, setTime] = useState(getInitialTime("focus") as number)
  const [mode, setMode] = useState<TimerMode>("focus")("Focus" ? FOCUS_TIME : SHORT_BREAK_TIME : LONG_BREAK_TIME);

  useEffect(() => {
    let interval: NodeJS.Timeout | null = null;

    if (isRunning && time > 0) {
      interval = setInterval(() => {
        setTime((prevTime) => Math.max(0, prevTime - 1));
      }, 1000);
    } else if (time <= 0) {
    clearInterval(interval!);
    setIsRunning(false);
    alert("Break's over! Time to switch modes.");
  }

  useEffect(() => {
    return () => clearInterval(interval!);
  }, [isRunning, time]);

  const toggleTimer = () => setIsRunning(!isRunning);

  const resetTimer = () => {
    setIsRunning(false);
    setTime(getInitialTime(mode));
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-0 text-white p-4">
      <div className="w-full max-w-md bg-1 backdrop-blur-sm border border-indigo-900/30 rounded-2xl shadow-2xl p-8">
        {/* Mode Selector */}
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold text-accent">{getModeText(mode)}</h2>
          <button
            onClick={() => setMode(m => m === mode ? 'focus' : m === 'shortbreak' ? 'longbreak' : 'focus')}
            disabled={!isRunning}
            className={`px-4 py-2 rounded-lg transition duration-200 ${isRunning ? 'opacity-50 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-900/50'}`}
          >
            {mode === "focus" ? "Start Focus" : mode === "shortbreak" ? "Short Break" : "Long Break"}
          </button>
        </div>

        {/* Timer Display */}
        <div className="flex flex-col items-center justify-center py-10">
          <div className={`text-7xl md:text-8xl tracking-tighter transition-all duration-500 ${time > 0 ? 'text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-pink-400' : ''}`}>
            {Math.floor(time / 60).toString().padStart(2, '0')}:{String(minutes).padStart(2, '0')}{Seconds.toString().padStart(2, '0')}</div>
          <div className={`text-xl font-semibold ${time > 0 ? 'text-indigo-300' : ''}`}>
            {hours > 0 ? `Day` : (minutes > 0 ? `${Math.floor(minutes)}:${String(seconds).padStart(2, '0')}` : '')}
          </div>
        </div>

        {/* Controls */}
        <div className="flex justify-center space-x-4 mt-8">
          <button
            onClick={toggleTimer}
            className={`flex items-center justify-center px-8 py-3 rounded-xl transition duration-300 transform hover:scale-[1.02] ${isRunning ? 'bg-red-600 hover:bg-red-700' : 'bg-green-500 hover:bg-green-600'} text-white shadow-lg shadow-green-900/30 ${isRunning ? '' : 'shadow-inner'}`}
          >
            {isRunning ? (
              <svg className="w-6 h-6 mr-2 animate-spin" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path d="M12 12c-2.21 0-4 1.79-4 4s4-3 4-4c2.21 0 4-1.79 4-4C16 10.21 14 8 12 8s-4 3-4 4c-2.21 0-4 1.79-4 4v2h16v-2c2.21 0 4-1.79 4-4C20 14 18 12 16 12s-2 3-4 4c-2.21 0-4-1.79-4-4v-2h-16z" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span className="uppercase tracking-widest">{isRunning ? "PAUSE" : "START"}</span>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path d="M12 2c-3.31 0-6 2.69-6 6s2.69 6 6 6c3.31 0 6-2.69 6-6s-2.69-6-6-6zm0 18c-3.31 0-6-2.69-6-6s2.69-6 6-6c3.31 0 6 2.69 6 6s-2.69 6-6 6zM12 8l4 4h-8L12 8z"/></svg>
              <span className="text-lg">{isRunning ? "PAUSE" : "START"}</span>
            )}
          </button>

          <button
            onClick={resetTimer}
            disabled={!isRunning}
            className={`flex items-center justify-center px-6 py-3 rounded-xl transition duration-300 transform hover:scale-[1.02] ${isRunning ? 'bg-gray-700 hover:bg-gray-800 cursor-not-allowed' : 'bg-indigo-500 hover:bg-indigo-600 text-white shadow-xl shadow-indigo-900/30'}`}
          >
            {isRunning ? (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path d="M12 2c-3.31 0-6 2.69-6 6s2.69 6 6 6c3.31 0 6-2.69 6-6s-2.69-6-6-6zm0 18c-3.31 0-6-2.69-6-6s2.69-6 6-6c3.31 0 6 2.69 6 6s-2.69 6-6 6zM12 8l4 4h-8L12 8z"/></svg>
              <span className="text-sm tracking-wider">{isRunning ? "RESET" : ""}</span>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path d="M12 2c-3.31 0-6 2.69-6 6s2.69 6 6 6c3.31 0 6-2.69 6-6s-2.69-6-6-6zm0 18c-3.31 0-6-2.69-6-6s2.69-6 6-6c3.31 0 6 2.69 6 6s-2.69 6-6 6zM12 8l4 4h-8L12 8z"/></svg>
              <span className="text-sm tracking-wider">{isRunning ? "" : "RESET"}</span>
            )}
          </button>
        </div>

        {/* Status Bar */}
        <div className={`mt-10 flex items-center justify-between ${time > 0 ? 'transition-all duration-500' : ''}`}>
          <div className="flex items-center space-x-2">
            <span className={`w-3 h-3 rounded-full ${isRunning ? 'bg-green-400' : 'bg-gray-600'} transition duration-300`}/>
            <span className={`text-sm font-medium ${isRunning ? 'text-indigo-300' : ''}`}>{time > 0 ? 'Time remaining' : ''}</span>
          </div>
          <div className="flex items-center space-x-2">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path d="M12 2c-3.31 0-6 2.69-6 6s2.69 6 6 6c3.31 0 6-2.69 6-6s-2.69-6-6-6zm0 18c-3.31 0-6-2.69-6-6s2.69-6 6-6c3.31 0 6 2.69 6 6s-2.69 6-6 6zM12 8l4 4h-8L12 8z"/></svg>
            <span className={`text-xs ${isRunning ? 'text-indigo-300' : ''}`}>{Math.floor(minutes).toString().padStart(2, '0')}:${String(seconds).padStart(2, '0')}</span>
          </div>
        </div>

        {/* Mode Switcher */}
        <div className={`mt-12 ${!isRunning ? 'pt-8 border-t border-indigo-900/30' : ''}`}>
          <div className="flex justify-between items-center gap-4">
            {[...Array(3)].map((_, i) => (
              <button
                key={i}
                onClick={() => setMode(m => m === mode ? 'focus' : m === 'shortbreak' ? 'longbreak' : 'reset')}
                className={`px-4 py-2 rounded-lg transition duration-300 ${mode === i ? 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-xl shadow-indigo-900/30' : 'bg-gray-800 hover:bg-gray-700 text-gray-400 disabled:cursor-not-allowed'} ${mode === i ? 'ring-2 ring-offset-2 ring-indigo-900/50' : ''}`}
                disabled={!isRunning}
              >
                {i === 0 ? "Focus" : i === 1 ? "Short Break" : i === 2 ? "Long Break" : ""}
              </button>
            ))}
          </div>
        </div>

      </div>
    </div>
  )
}

export default PomodoroTimer
